import React from 'react';

const Footer = () => {
  const scrollTo = (id) => {
    document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' });
  };

  return (
    <>
      {/* CSS inside same file */}
      <style>{`
        .footer {
          background: var(--deep-teal);
          color: rgba(255,255,255,0.7);
        }

        .footer__top {
          padding: 72px 0 56px;
          border-bottom: 1px solid rgba(255,255,255,0.08);
        }

        .footer__grid {
          display: grid;
          grid-template-columns: 1.8fr 1fr 1fr 1.5fr;
          gap: 48px;
        }

        .footer__logo {
          display: flex;
          align-items: center;
          gap: 10px;
          margin-bottom: 16px;
        }

        .footer__logo-icon {
          color: var(--gold);
          font-size: 1.2rem;
        }

        .footer__logo-name {
          font-family: 'Cormorant Garamond', serif;
          font-size: 1.3rem;
          color: white;
          letter-spacing: 0.05em;
        }

        .footer__brand-desc {
          font-size: 0.85rem;
          line-height: 1.8;
          color: rgba(255,255,255,0.5);
          max-width: 280px;
          margin-bottom: 24px;
        }

        .footer__socials {
          display: flex;
          gap: 10px;
        }

        .footer__social {
          width: 36px;
          height: 36px;
          border: 1px solid rgba(255,255,255,0.12);
          display: flex;
          align-items: center;
          justify-content: center;
          color: rgba(255,255,255,0.5);
          text-decoration: none;
          font-size: 0.85rem;
          font-weight: 700;
          transition: all 0.3s ease;
        }

        .footer__social:hover {
          background: var(--gold);
          border-color: var(--gold);
          color: white;
        }

        .footer__col-title {
          font-family: 'Jost', sans-serif;
          font-size: 0.7rem;
          letter-spacing: 0.2em;
          text-transform: uppercase;
          color: var(--gold);
          margin-bottom: 20px;
          font-weight: 600;
        }

        .footer__links {
          list-style: none;
          display: flex;
          flex-direction: column;
          gap: 10px;
        }

        .footer__links li button {
          background: none;
          border: none;
          cursor: pointer;
          font-family: 'Jost', sans-serif;
          font-size: 0.85rem;
          color: rgba(255,255,255,0.55);
          padding: 0;
          transition: color 0.3s;
          text-align: left;
        }

        .footer__links li button:hover {
          color: var(--gold);
        }

        .footer__links--plain li span {
          font-size: 0.85rem;
          color: rgba(255,255,255,0.55);
        }

        .footer__contact-items {
          display: flex;
          flex-direction: column;
          gap: 12px;
          margin-bottom: 24px;
        }

        .footer__contact-item {
          display: flex;
          gap: 10px;
          font-size: 0.82rem;
          color: rgba(255,255,255,0.55);
          line-height: 1.5;
        }

        .footer__newsletter p {
          font-size: 0.75rem;
          color: rgba(255,255,255,0.4);
          margin-bottom: 10px;
          letter-spacing: 0.05em;
        }

        .footer__newsletter-row {
          display: flex;
        }

        .footer__newsletter-row input {
          flex: 1;
          padding: 10px 14px;
          background: rgba(255,255,255,0.06);
          border: 1px solid rgba(255,255,255,0.12);
          border-right: none;
          color: white;
          font-family: 'Jost', sans-serif;
          font-size: 0.82rem;
          outline: none;
        }

        .newsletter-btn {
          padding: 10px 16px;
          background: var(--gold);
          border: none;
          color: white;
          font-size: 1rem;
          cursor: pointer;
        }

        .footer__bottom {
          padding: 20px 0;
        }

        .footer__bottom-inner {
          display: flex;
          justify-content: space-between;
          align-items: center;
          gap: 16px;
          flex-wrap: wrap;
        }

        .footer__bottom p {
          font-size: 0.78rem;
          color: rgba(255,255,255,0.3);
        }

        .footer__bottom-links {
          display: flex;
          gap: 24px;
        }

        .footer__bottom-links a {
          font-size: 0.75rem;
          color: rgba(255,255,255,0.3);
          text-decoration: none;
        }

        .footer__bottom-links a:hover {
          color: var(--gold);
        }

        @media (max-width: 1024px) {
          .footer__grid {
            grid-template-columns: 1fr 1fr;
            gap: 40px;
          }
        }

        @media (max-width: 600px) {
          .footer__grid {
            grid-template-columns: 1fr;
          }

          .footer__bottom-inner {
            flex-direction: column;
            text-align: center;
          }
        }
      `}</style>

      {/* JSX unchanged */}
      <footer className="footer">
        <div className="footer__top">
          <div className="container">
            <div className="footer__grid">

              <div className="footer__brand">
                <div className="footer__logo">
                  <span className="footer__logo-icon">✦</span>
                  <span className="footer__logo-name">Sunset Resort</span>
                </div>
                <p className="footer__brand-desc">
                  A sanctuary of timeless elegance on the shores of the Maldives.
                </p>

                <div className="footer__socials">
                  {['Facebook','Instagram','Twitter','YouTube'].map((s)=>(
                    <a key={s} href="#" className="footer__social">{s[0]}</a>
                  ))}
                </div>
              </div>

              <div className="footer__col">
                <h4 className="footer__col-title">Quick Links</h4>
                <ul className="footer__links">
                  {['Home','About','Rooms','Gallery','Contact'].map((link)=>(
                    <li key={link}>
                      <button onClick={()=>scrollTo(link.toLowerCase())}>{link}</button>
                    </li>
                  ))}
                </ul>
              </div>

              <div className="footer__col">
                <h4 className="footer__col-title">Our Services</h4>
                <ul className="footer__links footer__links--plain">
                  {['Luxury Spa','Fine Dining','Water Sports'].map((s)=>(
                    <li key={s}><span>— {s}</span></li>
                  ))}
                </ul>
              </div>

              <div className="footer__col">
                <h4 className="footer__col-title">Contact</h4>
                <div className="footer__contact-items">
                  <div className="footer__contact-item">📍 Maldives</div>
                  <div className="footer__contact-item">📞 +960 123 456</div>
                  <div className="footer__contact-item">✉️ reservations@mail.com</div>
                </div>

                <div className="footer__newsletter">
                  <p>Subscribe</p>
                  <div className="footer__newsletter-row">
                    <input type="email" placeholder="your@email.com" />
                    <button className="newsletter-btn">→</button>
                  </div>
                </div>
              </div>

            </div>
          </div>
        </div>

        <div className="footer__bottom">
          <div className="container footer__bottom-inner">
            <p>© {new Date().getFullYear()} Sunset Resort</p>
          </div>
        </div>
      </footer>
    </>
  );
};

export default Footer;
